import pandas as pd
import re
from datetime import datetime

businesses = env['data_1']
ratings = env['data_2']

# Convert ratings to dict
rating_dict = {r['gmap_id']: r['avg_rating'] for r in ratings}

def is_open_after_6pm_weekday(hours_list):
    if not hours_list:
        return False

    weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

    for i in range(0, len(hours_list), 2):
        day = hours_list[i]
        if day not in weekdays:
            continue

        time_str = hours_list[i+1]
        if time_str == 'Closed':
            continue
        if time_str == 'Open 24 hours':
            return True

        # Parse time_str, e.g., '6:30AM–6PM' or '11AM–9:30PM'
        # Sometimes it's 'Open 24 hours'
        # Split by '–' or '-'
        parts = re.split(r'–|-', time_str)
        if len(parts) == 2:
            close_str = parts[1].strip()
            # Parse close_str
            try:
                # It could be '6PM', '9:30PM', '12AM'
                close_time = datetime.strptime(close_str, '%I:%M%p')
            except ValueError:
                try:
                    close_time = datetime.strptime(close_str, '%I%p')
                except ValueError:
                    continue

            # Check if after 6:00 PM
            # 6:00 PM is 18:00
            # 12AM is 00:00 (next day, so it's after 6PM)
            if close_time.hour > 18 or close_time.hour < 6: # < 6 means like 1AM, 2AM
                return True
            if close_time.hour == 18 and close_time.minute > 0:
                return True

    return False

results = []
for b in businesses:
    if is_open_after_6pm_weekday(b['hours']):
        gmap_id = b['gmap_id']
        if gmap_id in rating_dict:
            results.append({
                'name': b['name'],
                'hours': b['hours'],
                'avg_rating': rating_dict[gmap_id]
            })

results.sort(key=lambda x: x['avg_rating'], reverse=True)
top_5 = results[:5]
for r in top_5:
    print(f"{r['name']} | {r['avg_rating']} | {r['hours']}")

